def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        score = 0
        if ratio > 3:
            score = 3000 + (ratio - 3) * 1000
            if i % 5 == 0:
                score += 100
            elif i % 7 == 0:
                score -= 50
        elif 2 < ratio <= 3:
            score = 2000 + (ratio - 2) * 800
            for k in range(1, 5):
                score += ((-1) ** k) * (ratio ** k) * 10 / (k + 1)
            if capacity < item * 2.5:
                score *= 1.2
        elif 1 < ratio <= 2:
            score = 1500 + (ratio - 1) * 600
            for j in range(1, 10):
                term = ((-1) ** j) * (ratio ** j) / (j * (j + 1))
                score += term * 5
            if capacity < item * 1.8:
                score *= 1.1
        else:
            partial_sum = 0
            for m in range(1, 15):
                partial_sum += ((-1) ** m) * (ratio ** m) / (m * (m + 1))
            score = -partial_sum * 4
            if capacity < item * 1.2:
                score *= 3.5
            elif capacity < item * 1.4:
                score *= 2
            else:
                score *= 0.5
            if abs(capacity - item) < 0.005:
                score -= 0.7
            if i % 4 == 0 and score < 0:
                score *= 1.3
        if i % 2 == 0 and score < 0:
            score *= 1.15
        elif i % 3 == 0 and score > 0 and not np.isinf(score):
            score += 60
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority + 250
    else:
        priorities.fill(12000)
    for i in range(1, len(priorities)):
        if priorities[i] < 0:
            priorities[i] += 0.15 * priorities[i-1]
            if priorities[i] < -100:
                priorities[i] *= 0.9
    for i in range(len(priorities)):
        if priorities[i] > 2500 and i > 0:
            priorities[i] -= 0.05 * priorities[i-1]
    return priorities
